/*Template Author - Akshata*/#include<bits/stdc++.h>using namespace std;#define int long long const int maxN = 1000001;int spf[maxN]; void pre(){for(int i=0;i<maxN;i++)spf[i]=i;for(int i=2;i*i<maxN;i++)if(spf[i]==i)for(int j=i*i;j<maxN;j+=i)if(spf[j]==j)spf[j]=i;}void inparr(vector<int>&a,int n){for(int i=0;i<n;i++)cin>>a[i];} void solve(){    int n;    cin>>n;    vector<string> v(n);    for(int i=0;i<n;i++){        cin>>v[i];    }    string s = v[0];    int minops = 1e9;    int len = s.length();    for(int rot=0;rot<len;rot++){        string w = s;        for(int i=0;i<rot;i++){            w+=w[0];            w.erase(0,1);        }        int ops = 0;        bool flag = true;        // cout<<w<<" ";        for(int ind=0;ind<n;ind++){                        bool wformed = false;            for(int rot1=0;rot1<len;rot1++){                string ww = v[ind];                for(int j=0;j<rot1;j++){                    ww+=ww[0];                    ww.erase(0,1);                }                if(ww==w){                    // cout<<w<<" "<<ww<<" "<<rot1<<endl;                    wformed = true;                    ops+=rot1;                    break;                }            }            if(!wformed){                flag = false;                break;            }        }        if(flag){            // cout<<ops<<endl;            minops = min(ops,minops);        }else{            // cout<<"np"<<endl;        }    }    if(minops==1e9){        cout<<-1<<endl;    }    else        cout<<minops<<endl;} int32_t main(){ios_base::sync_with_stdio(false);cin.tie(NULL);// pre(); // Uncomment for Sieveint t=1;while(t--)solve();return 0;}